// Data/Configurations/UserConfiguration.cs
public class UserConfiguration : IEntityTypeConfiguration<User>
{
    public void Configure(EntityTypeBuilder<User> builder)
    {
        builder.ToTable("users");
        builder.HasKey(u => u.Id);

        builder.Property(u => u.Name)
            .IsRequired()
            .HasMaxLength(100);

        builder.Property(u => u.Email)
            .IsRequired()
            .HasMaxLength(255);

        builder.HasIndex(u => u.Email).IsUnique();

        builder.Property(u => u.CreatedAt)
            .HasDefaultValueSql("CURRENT_TIMESTAMP");

        builder.HasMany(u => u.Roles)
            .WithMany(r => r.Users)
            .UsingEntity<Dictionary<string, object>>(
                "user_roles",
                j => j.HasOne<Role>().WithMany().HasForeignKey("RoleId"),
                j => j.HasOne<User>().WithMany().HasForeignKey("UserId")
            );

        builder.HasMany(u => u.Orders)
            .WithOne(o => o.User)
            .HasForeignKey(o => o.UserId)
            .OnDelete(DeleteBehavior.SetNull);
    }
}

public interface IUserRepository
{
    Task<User?> GetByIdAsync(int id);
    Task<User?> GetByEmailAsync(string email);
    Task<PagedResult<User>> GetPagedAsync(int page, int pageSize);
    Task AddAsync(User user);
    void Remove(User user);
    Task SaveChangesAsync();
}

public async Task<PagedResult<User>> GetPagedAsync(int page, int pageSize)
{
    var query = _context.Users
        .AsNoTracking()
        .OrderByDescending(u => u.CreatedAt);

    var totalCount = await query.CountAsync();
    var items = await query
        .Skip((page - 1) * pageSize)
        .Take(pageSize)
        .ToListAsync();

    return new PagedResult<User>(items, totalCount, page, pageSize);
}

# safe-migration.sh: generate migration SQL and block on destructive ops
dotnet ef migrations add "$NAME" --project "$PROJ" --no-build
SCRIPT=$(mktemp).sql
dotnet ef migrations script --idempotent --project "$PROJ" -o "$SCRIPT"
grep -iE 'DROP|CASCADE|TRUNCATE|RENAME COLUMN' "$SCRIPT" && {
  echo "DESTRUCTIVE OPS DETECTED — human approval required"; exit 2;
} || echo "Migration looks safe (auto-check only)"
